import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const h=JSON.parse('{"title":"素材一覧","description":"","frontmatter":{},"headers":[],"relativePath":"ja/items/materials.md","filePath":"ja/items/materials.md","lastUpdated":1775394001000}'),i={name:"ja/items/materials.md"};function s(n,t,r,y,f,x){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="素材一覧" tabindex="-1">素材一覧 <a class="header-anchor" href="#素材一覧" aria-label="Permalink to &quot;素材一覧&quot;">​</a></h1><p>育成・強化に使用する素材の一覧と入手方法です。</p><h2 id="覚醒体育成素材" tabindex="-1">覚醒体育成素材 <a class="header-anchor" href="#覚醒体育成素材" aria-label="Permalink to &quot;覚醒体育成素材&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">素材</th><th style="text-align:left;">用途</th><th style="text-align:left;">主な入手先</th></tr></thead><tbody><tr><td style="text-align:left;">霊知制剤 I (Gnosis Elixir I)</td><td style="text-align:left;">低級経験素材。溢れた分は最低級制剤で返還（500以下は四捨五入で500に）</td><td style="text-align:left;">融蝕之墟、メインステージ</td></tr><tr><td style="text-align:left;">霊知制剤 II (Gnosis Elixir II)</td><td style="text-align:left;">中級経験素材</td><td style="text-align:left;">融蝕之墟、イベント</td></tr><tr><td style="text-align:left;">霊知制剤 III (Gnosis Elixir III)</td><td style="text-align:left;">高級経験素材</td><td style="text-align:left;">融蝕之墟（上級）</td></tr><tr><td style="text-align:left;">特批薬剤 (Special Approval Elixir)</td><td style="text-align:left;">高級経験素材</td><td style="text-align:left;">調査行動チャプター報酬（第1章=5個、第6章=35個）</td></tr></tbody></table><h2 id="昇格-突破-素材" tabindex="-1">昇格（突破）素材 <a class="header-anchor" href="#昇格-突破-素材" aria-label="Permalink to &quot;昇格（突破）素材&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">素材</th><th style="text-align:left;">用途</th><th style="text-align:left;">主な入手先</th></tr></thead><tbody><tr><td style="text-align:left;">初階昇格匣子 (Basic Ascension Casket)</td><td style="text-align:left;">初級昇格素材（レベル10初回突破）</td><td style="text-align:left;">融蝕之墟</td></tr><tr><td style="text-align:left;">中階昇格匣子 (Intermediate Ascension Casket)</td><td style="text-align:left;">中級昇格素材</td><td style="text-align:left;">融蝕之墟</td></tr><tr><td style="text-align:left;">高階昇格匣子 (Advanced Ascension Casket)</td><td style="text-align:left;">高級昇格素材</td><td style="text-align:left;">融蝕之墟（上級）</td></tr><tr><td style="text-align:left;">幸运糖果 (Lucky Candy)</td><td style="text-align:left;">界域突破素材。回溯時に擬態凝晶30個に変換</td><td style="text-align:left;">界域専用ステージ</td></tr><tr><td style="text-align:left;">蜡像泥胚 (Wax Figure Clay)</td><td style="text-align:left;">界域突破素材。回溯時に擬態凝晶30個に変換</td><td style="text-align:left;">界域専用ステージ</td></tr><tr><td style="text-align:left;">漆黑锁扣 (Pitch-Black Clasp)</td><td style="text-align:left;">界域突破素材。回溯時に擬態凝晶30個に変換</td><td style="text-align:left;">界域専用ステージ</td></tr><tr><td style="text-align:left;">维度结晶 (Dimension Crystal)</td><td style="text-align:left;">界域突破素材。回溯時に擬態凝晶30個に変換</td><td style="text-align:left;">界域専用ステージ</td></tr><tr><td style="text-align:left;">虔诚圣心 (Devout Sacred Heart)</td><td style="text-align:left;">界域突破素材。回溯時に擬態凝晶30個に変換</td><td style="text-align:left;">界域専用ステージ</td></tr><tr><td style="text-align:left;">贤者之石 (Philosopher&#39;s Stone)</td><td style="text-align:left;">汎用レア突破素材</td><td style="text-align:left;">高難度コンテンツ</td></tr><tr><td style="text-align:left;">原初霊核 (Primordial Spirit Core)</td><td style="text-align:left;">霊知深化素材（レベル上限60→70）。深化には1核+界域昇格素材+蔷薇金券が必要</td><td style="text-align:left;">沈澱ショップ（25碎片=1核、3回/月）</td></tr><tr><td style="text-align:left;">精粹原初霊核 (Refined Primordial Spirit Core)</td><td style="text-align:left;">高級霊知深化素材</td><td style="text-align:left;">高難度コンテンツ</td></tr></tbody></table><h2 id="カード強化素材" tabindex="-1">カード強化素材 <a class="header-anchor" href="#カード強化素材" aria-label="Permalink to &quot;カード強化素材&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">素材</th><th style="text-align:left;">用途</th><th style="text-align:left;">主な入手先</th></tr></thead><tbody><tr><td style="text-align:left;">カード素材（低）</td><td style="text-align:left;">Lv.2強化</td><td style="text-align:left;">メインステージ、資源ステージ</td></tr><tr><td style="text-align:left;">カード素材（中）</td><td style="text-align:left;">Lv.3強化</td><td style="text-align:left;">資源ステージ、派遣</td></tr><tr><td style="text-align:left;">カード素材（高）</td><td style="text-align:left;">Lv.4強化</td><td style="text-align:left;">チャレンジステージ、イベント</td></tr><tr><td style="text-align:left;">カード素材（極）</td><td style="text-align:left;">Lv.5強化</td><td style="text-align:left;">チャレンジステージ（高難度）</td></tr><tr><td style="text-align:left;">特殊素材</td><td style="text-align:left;">Lv.6強化</td><td style="text-align:left;">チャレンジステージ、冶錬室</td></tr></tbody></table><h2 id="スキル素材" tabindex="-1">スキル素材 <a class="header-anchor" href="#スキル素材" aria-label="Permalink to &quot;スキル素材&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">素材</th><th style="text-align:left;">用途</th><th style="text-align:left;">主な入手先</th></tr></thead><tbody><tr><td style="text-align:left;">初階技能補給 (Basic Skill Supply)</td><td style="text-align:left;">低級スキル素材（アカウントLv.25解放）</td><td style="text-align:left;">融蝕之墟</td></tr><tr><td style="text-align:left;">中階技能補給 (Intermediate Skill Supply)</td><td style="text-align:left;">中級スキル素材</td><td style="text-align:left;">融蝕之墟</td></tr><tr><td style="text-align:left;">高階技能補給 (Advanced Skill Supply)</td><td style="text-align:left;">高級スキル素材</td><td style="text-align:left;">融蝕之墟（上級）</td></tr><tr><td style="text-align:left;">混沌残渣 (Chaotic Residue)</td><td style="text-align:left;">混沌界域スキル素材</td><td style="text-align:left;">混沌融蝕之墟 / 混沌聚落</td></tr><tr><td style="text-align:left;">深渕残渣 (Abyssal Residue)</td><td style="text-align:left;">深海界域スキル素材</td><td style="text-align:left;">深海融蝕之墟 / 波纳佩遗迹</td></tr><tr><td style="text-align:left;">血腥残渣 (Bloody Residue)</td><td style="text-align:left;">血肉界域スキル素材</td><td style="text-align:left;">血肉融蝕之墟 / 蠕虫巢穴</td></tr><tr><td style="text-align:left;">宇宙残渣 (Cosmic Residue)</td><td style="text-align:left;">超維界域スキル素材</td><td style="text-align:left;">超維融蝕之墟 / 史瓦西之喉</td></tr></tbody></table><h2 id="装備強化素材" tabindex="-1">装備強化素材 <a class="header-anchor" href="#装備強化素材" aria-label="Permalink to &quot;装備強化素材&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">素材</th><th style="text-align:left;">用途</th><th style="text-align:left;">主な入手先</th></tr></thead><tbody><tr><td style="text-align:left;">千面印章 (Thousand-Face Seal)</td><td style="text-align:left;">密契強化・写本素材。36個で密契を+0→+12まで強化可能。写本1回=3個+蔷薇金券7500</td><td style="text-align:left;">課程、イベント</td></tr><tr><td style="text-align:left;">擬態凝晶 (Mimetic Crystal)</td><td style="text-align:left;">汎用合成素材。30個=高級スキル素材1個。回溯時に突破素材が30:1で返還</td><td style="text-align:left;">課程進階、沈澱/深潜/蔷薇金券ショップ</td></tr><tr><td style="text-align:left;">追念羽筆 (Memory Quill)</td><td style="text-align:left;">汎用育成素材（Lv.55以降解放）。毎週5つのショップから各5-10個購入可能（合計25-50個/週）</td><td style="text-align:left;">各種ショップ交換</td></tr></tbody></table><h2 id="教化素材" tabindex="-1">教化素材 <a class="header-anchor" href="#教化素材" aria-label="Permalink to &quot;教化素材&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">素材</th><th style="text-align:left;">用途</th><th style="text-align:left;">主な入手先</th></tr></thead><tbody><tr><td style="text-align:left;">蒼白筆記 (Pale Note)</td><td style="text-align:left;">低級教化素材（3個=1蒼白卷宗）</td><td style="text-align:left;">融蝕之墟、ステージドロップ</td></tr><tr><td style="text-align:left;">蒼白卷宗 (Pale File)</td><td style="text-align:left;">中級教化素材（3個=1蒼白典籍）</td><td style="text-align:left;">融蝕之墟</td></tr><tr><td style="text-align:left;">蒼白典籍 (Pale Tome)</td><td style="text-align:left;">高級教化素材</td><td style="text-align:left;">融蝕之墟（上級）</td></tr><tr><td style="text-align:left;">淬煉理智 (Tempered Reason)</td><td style="text-align:left;">淬煉系列教化素材</td><td style="text-align:left;">高難度コンテンツ</td></tr><tr><td style="text-align:left;">淬煉精神 (Tempered Spirit)</td><td style="text-align:left;">高級淬煉系列教化素材</td><td style="text-align:left;">高難度コンテンツ</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>素材の効率的な収集ルートは<a href="./../guides/dailies.html">デイリー攻略</a>で解説しています。低級素材3個=高級素材1個で合成可能です（錬金システム）。</p></div><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">アイテム概要</a></li><li><a href="./../awakeners/leveling.html">育成ガイド</a></li><li><a href="./../cards/upgrade.html">カード強化</a></li><li><a href="./../stages/resource.html">資源ステージ</a></li></ul>',17)])])}const o=e(i,[["render",s]]);export{h as __pageData,o as default};
